values.content:
=Bitte analysiere und beantworte diese Bewertung:

Bewertung von: {{ $json.reviewerName }}
Sterne: {{ $json.rating }}/5
Titel: {{ $json.reviewTitle }}
Text: {{ $json.reviewText }}
Datum: {{ $json.reviewDate }}

parameters.jsCode:
const aiRaw = $input.first().json.content?.[0]?.text ?? $input.first().json.text ?? '';

let parsed;
try {
  // Extract JSON from potential markdown code blocks
  const jsonMatch = aiRaw.match(/```json\n?([\s\S]*?)\n?```/) || aiRaw.match(/({[\s\S]*})/);
  const jsonString = jsonMatch ? jsonMatch[1] ?? jsonMatch[0] : aiRaw;
  parsed = JSON.parse(jsonString.trim());
} catch (e) {
  parsed = {
    sentiment: 'neutral',
    sentimentScore: 5,
    reasoning: 'Parse-Fehler: ' + e.message,
    suggestedResponse: 'Vielen Dank für Ihre Bewertung. Wir werden uns schnellstmöglich darum kümmern.'
  };
}

const prevData = $('Extract & Normalize Review').first().json;

return [{
  json: {
    ...prevData,
    sentiment: parsed.sentiment ?? 'neutral',
    sentimentScore: parsed.sentimentScore ?? 5,
    aiReasoning: parsed.reasoning ?? '',
    suggestedResponse: parsed.suggestedResponse ?? '',
    processedAt: new Date().toISOString(),
    status: 'pending_approval'
  }
}];

const items = $input.all();
const today = new Date();
const last7 = new Date(today);
last7.setDate(today.getDate() - 7);

const recent = items.filter(i => {
  const ts = new Date(i.json.timestamp);
  return ts >= last7;
});

if (recent.length === 0) {
  return [{ json: { reportHtml: '<p>Keine Reviews in den letzten 7 Tagen.</p>', totalReviews: 0 } }];
}

const scores = recent.map(i => parseFloat(i.json.sentiment_score) || 5);
const avgScore = (scores.reduce((a, b) => a + b, 0) / scores.length).toFixed(1);
const ratings = recent.map(i => parseFloat(i.json.rating) || 3);
const avgRating = (ratings.reduce((a, b) => a + b, 0) / ratings.length).toFixed(1);

const positive = recent.filter(i => i.json.sentiment === 'positiv').length;
const neutral = recent.filter(i => i.json.sentiment === 'neutral').length;
const negative = recent.filter(i => i.json.sentiment === 'negativ').length;

const published = recent.filter(i => i.json.status === 'published').length;
const pending = recent.filter(i => i.json.status === 'pending_approval').length;
const rejected = recent.filter(i => i.json.status === 'rejected').length;

const negativeReviews = recent
  .filter(i => i.json.sentiment === 'negativ')
  .map(i => `<li><strong>${i.json.reviewer}</strong> (${i.json.rating}⭐): ${(i.json.review_text || '').substring(0, 100)}...</li>`)
  .join('');

const reportHtml = `
<html><body style="font-family: Arial, sans-serif; max-width: 700px; margin: auto; color: #333;">
<h1>📊 Sentiment Report – Letzte 7 Tage</h1>
<p>Zeitraum: ${last7.toLocaleDateString('de-DE')} – ${today.toLocaleDateString('de-DE')}</p>

<h2>Übersicht</h2>
<table style="width:100%; border-collapse:collapse; margin-bottom:20px;">
<tr style="background:#f0f0f0;"><td style="padding:10px; border:1px solid #ddd;"><strong>Gesamt Reviews</strong></td><td style="padding:10px; border:1px solid #ddd;">${recent.length}</td></tr>
<tr><td style="padding:10px; border:1px solid #ddd;"><strong>Ø Sterne</strong></td><td style="padding:10px; border:1px solid #ddd;">${avgRating}/5</td></tr>
<tr style="background:#f0f0f0;"><td style="padding:10px; border:1px solid #ddd;"><strong>Ø Sentiment-Score</strong></td><td style="padding:10px; border:1px solid #ddd;">${avgScore}/10</td></tr>
</table>

<h2>Sentiment-Verteilung</h2>
<table style="width:100%; border-collapse:collapse; margin-bottom:20px;">
<tr><td style="padding:10px; border:1px solid #ddd; background:#d4edda;">✅ Positiv</td><td style="padding:10px; border:1px solid #ddd;">${positive} (${((positive/recent.length)*100).toFixed(0)}%)</td></tr>
<tr><td style="padding:10px; border:1px solid #ddd; background:#fff3cd;">⚠️ Neutral</td><td style="padding:10px; border:1px solid #ddd;">${neutral} (${((neutral/recent.length)*100).toFixed(0)}%)</td></tr>
<tr><td style="padding:10px; border:1px solid #ddd; background:#f8d7da;">❌ Negativ</td><td style="padding:10px; border:1px solid #ddd;">${negative} (${((negative/recent.length)*100).toFixed(0)}%)</td></tr>
</table>

<h2>Response-Status</h2>
<table style="width:100%; border-collapse:collapse; margin-bottom:20px;">
<tr><td style="padding:10px; border:1px solid #ddd;">✅ Veröffentlicht</td><td style="padding:10px; border:1px solid #ddd;">${published}</td></tr>
<tr><td style="padding:10px; border:1px solid #ddd;">⏳ Ausstehend</td><td style="padding:10px; border:1px solid #ddd;">${pending}</td></tr>
<tr><td style="padding:10px; border:1px solid #ddd;">❌ Abgelehnt</td><td style="padding:10px; border:1px solid #ddd;">${rejected}</td></tr>
</table>

${negative > 0 ? `<h2>⚠️ Negative Reviews (Handlungsbedarf)</h2><ul>${negativeReviews}</ul>` : '<h2>✅ Keine negativen Reviews – Gut gemacht!</h2>'}

<p style="color:#888; font-size:12px; margin-top:30px;">Automatisch generiert von AEVUM Review-Responder | ${today.toISOString()}</p>
</body></html>`;

return [{ json: { reportHtml, totalReviews: recent.length, avgScore, avgRating, positive, neutral, negative } }];

